```typescript
import Conf from 'conf';
import chalk from 'chalk';

interface BrainShieldConfig {
  anthropicApiKey: string;
  model: string;
  maxScanCost: number;
  maxTokens: number;
}

const config = new Conf<BrainShieldConfig>({
  projectName: 'brainshield',
  defaults: {
    anthropicApiKey: '',
    model: 'claude-opus-4-6',
    maxScanCost: 5.0,
    maxTokens: 100000,
  },
});

/**
 * Retrieves API key with secure precedence:
 * 1. Environment variable (preferred)
 * 2. Local config store (with warning)
 * 3. Throws error if neither exists
 */
export function getApiKey(): string {
  // Always prefer environment variable
  const envKey = process.env.ANTHROPIC_API_KEY;
  if (envKey && envKey.trim().length > 0) {
    return envKey.trim();
  }

  // Fall back to stored key with security warning
  const storedKey = config.get('anthropicApiKey');
  if (storedKey && storedKey.trim().length > 0) {
    console.warn(
      chalk.yellow(
        '⚠  Using locally stored API key (plaintext on disk). ' +
        'For better security, set the ANTHROPIC_API_KEY environment variable instead.'
      )
    );
    return storedKey.trim();
  }

  throw new Error(
    'No API key configured.\n' +
    '  Option 1: export ANTHROPIC_API_KEY=your-key-here\n' +
    '  Option 2: brain config set-key <your-key>'
  );
}

/**
 * Validates API key format before storing
 */
export function setApiKey(key: string): void {
  const trimmed = key.trim();

  if (trimmed.length === 0) {
    throw new Error('API key cannot be empty.');
  }

  // Basic format validation for Anthropic keys
  if (!trimmed.startsWith('sk-ant-') && !trimmed.startsWith('sk-')) {
    console.warn(
      chalk.yellow('⚠  API key does not match expected Anthropic format (sk-ant-*). Storing anyway.')
    );
  }

  config.set('anthropicApiKey', trimmed);
}

/**
 * Clears stored API key from disk
 */
export function clearApiKey(): void {
  config.set('anthropicApiKey', '');
}

export { config };
export type { BrainShieldConfig };
```

