## File 4: `packages/cli/src/agents/scanners/auth.ts`

> **Note:** I'm providing the security wrapper/safeguards to add around your existing scanner logic. Wrap your existing scanning functions with these protections.

```typescript
import chalk from 'chalk';

// ── Security Limits ──────────────────────────────────────────────
const MAX_FILE_SIZE = 1024 * 1024; // 1MB - skip files larger than this
const MAX_FILES_PER_SCAN = 500;    // prevent runaway scans
const REGEX_TIMEOUT_MS = 5000;      // timeout for regex operations per file

interface ScanFinding {
  file: string;
  line: number;
  severity: 'critical' | 'high' | 'medium' | 'low';
  rule: string;
  message: string;
  snippet: string;
  falsePositive?: boolean;
  fix?: string;
}

/**
 * Safely execute a regex scan with timeout protection against ReDoS
 */
function safeRegexScan(
  content: string,
  pattern: RegExp,
  filePath: string,
): RegExpExecArray[] {
  const results: RegExpExecArray[] = [];
  const startTime = Date.now();

  // Clone the regex to avoid shared state issues
  const regex = new RegExp(pattern.source, pattern.flags);

  let match: RegExpExecArray | null;
  while ((match = regex.exec(content)) !== null) {
    // Timeout check to prevent ReDoS
    if (Date.now() - startTime > REGEX_TIMEOUT_MS) {
      console.warn(
        chalk.yellow(`⚠  Regex timeout scanning ${filePath} with pattern ${pattern.source.slice(0, 40)}...`)
      );
      break;
    }

    results.push(match);

    // Prevent infinite loops on zero-length matches
    if (match[0].length === 0) {
      regex.lastIndex++;
    }
  }

  return results;
}

/**
 * Validates a file before scanning
 * Returns null if file should be skipped, or the content if safe to scan
 */
function validateFileForScan(
  filePath: string,
  content: string,
): string | null {
  // Skip empty files
  if (!content || content.trim().length === 0) {
    return null;
  }

  // Skip files that are too large (likely bundled/minified)
  if (content.length > MAX_FILE_SIZE) {
    console.warn(
      chalk.yellow(`⚠  Skipping ${filePath}: file too large (${(content.length / 1024).toFixed(0)}KB > ${(MAX_FILE_SIZE / 1024).toFixed(0)}KB limit)`)
    );
    return null;
  }

  // Skip binary files (check for null bytes)
  if (content.includes('\0')) {
    return null;
  }

  // Skip node_modules, dist, build outputs
  const skipPaths = ['node_modules', '/dist/', '/build/', '/.next/', '/coverage/'];
  if (skipPaths.some((p) => filePath.includes(p))) {
    return null;
  }

  return content;
}

/**
 * Deduplicate findings by file + line + rule
 */
function deduplicateFindings(findings: ScanFinding[]): ScanFinding[] {
  const seen = new Set<string>();
  return findings.filter((finding) => {
    const key = `${finding.file}:${finding.line}:${finding.rule}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

// ── Auth Security Patterns ───────────────────────────────────────
// Using simpler, non-backtracking patterns to avoid ReDoS

const AUTH_PATTERNS: Array<{
  pattern: RegExp;
  rule: string;
  severity: ScanFinding['severity'];
  message: string;
  fix: string;
}> = [
  {
    pattern: /jwt\.verify\s*\(\s*[^,]+,\s*['"][^'"]{1,50}['"]/gi,
    rule: 'hardcoded-jwt-secret',
    severity: 'critical',
    message: 'JWT secret appears to be hardcoded. Use environment variables.',
    fix: 'Move the secret to an environment variable: process.env.JWT_SECRET',
  },
  {
    pattern: /(['"])(sk[-_]live|sk[-_]test|sk-ant-|ghp_|gho_|AKIA)[A-Za-z0-9]{8,}['"]*/gi,
    rule: 'hardcoded-secret-key',
    severity: 'critical',
    message: 'Potential hardcoded API key/secret detected.',
    fix: 'Move secrets to environment variables and add to .gitignore/.env.example',
  },
  {
    pattern: /localStorage\.(setItem|getItem)\s*\(\s*['"][^'"]*token[^'"]*['"]/gi,
    rule: 'localstorage-token',
    severity: 'high',
    message: 'Auth token stored in localStorage is vulnerable to XSS.',
    fix: 'Use httpOnly cookies for token storage instead of localStorage.',
  },
  {
    pattern: /cookie[^}]*secure\s*:\s*false/gi,
    rule: 'insecure-cookie',
    severity: 'high',
    message: 'Cookie set without secure flag.',
    fix: 'Set secure: true and httpOnly: true on authentication cookies.',
  },
  {
    pattern: /cookie[^}]*httpOnly\s*:\s*false/gi,
    rule: 'no-httponly-cookie',
    severity: 'high',
    message: 'Cookie set without httpOnly flag, vulnerable to XSS theft.',
    fix: 'Set httpOnly: true on all authentication cookies.',
  },
  {
    pattern: /csrf|xsrf/i, // Broad check - refine during LLM enrichment
    rule: 'csrf-check',
    severity: 'medium',
    message: 'CSRF-related code detected. Verify proper CSRF protection is in place.',
    fix: 'Ensure CSRF tokens are validated on all state-changing endpoints.',
  },
  {
    pattern: /password\s*[=:]\s*['"][^'"]+['"]/gi,
    rule: 'hardcoded-password',
    severity: 'critical',
    message: 'Possible hardcoded password detected.',
    fix: 'Remove hardcoded passwords. Use environment variables or a secrets manager.',
  },
  {
    pattern: /algorithm\s*[=:]\s*['"]none['"]/gi,
    rule: 'jwt-alg-none',
    severity: 'critical',
    message: 'JWT algorithm set to "none" allows token forgery.',
    fix: 'Always specify a strong algorithm like RS256 or HS256.',
  },
];

/**
 * Main auth scanner function with all security safeguards
 */
export async function scanAuthVulnerabilities(
  files: Map<string, string>,
): Promise<ScanFinding[]> {
  const findings: ScanFinding[] = [];
  let filesScanned = 0;

  for (const [filePath, rawContent] of files) {
    // Enforce file limit
    if (filesScanned >= MAX_FILES_PER_SCAN) {
      console.warn(
        chalk.yellow(`⚠  File limit reached (${MAX_FILES_PER_SCAN}). Stopping scan.`)
      );
      break;
    }

    // Validate file
    const content = validateFileForScan(filePath, rawContent);
    if (!content) continue;

    filesScanned++;

    // Run each pattern with timeout protection
    for (const { pattern, rule, severity, message, fix } of AUTH_PATTERNS) {
      const matches = safeRegexScan(content, pattern, filePath);

      for (const match of matches) {
        const lineNumber = content.substring(0, match.index).split('\n').length;
        const lineContent = content.split('\n')[lineNumber - 1] || '';

        findings.push({
          file: filePath,
          line: lineNumber,
          severity,
          rule,
          message,
          snippet: lineContent.trim().substring(0, 200), // Limit snippet length
          fix,
        });
      }
    }
  }

  // Deduplicate before returning (or sending to LLM for enrichment)
  const deduped = deduplicateFindings(findings);

  console.log(
    chalk.dim(`Scanned ${filesScanned} files, found ${deduped.length} potential auth issues.`)
  );

  return deduped;
}

export { safeRegexScan, validateFileForScan, deduplicateFindings };
export type { ScanFinding };
```

