import { clerkMiddleware, createRouteMatcher } from '@clerk/nextjs/server';
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

// ✅ FIX 1: Protection de TOUTES les routes sensibles (pas seulement /dashboard)
const isProtectedRoute = createRouteMatcher([
  '/dashboard(.*)',      // Dashboard et sous-pages
  '/settings(.*)',       // Paramètres utilisateur
  '/api/dashboard(.*)',  // API dashboard
  '/api/user(.*)',       // API utilisateur
  '/api/reports(.*)',    // API rapports
  '/api/scans(.*)',      // API scans
]);

// ✅ FIX 2: Routes publiques explicites
const isPublicRoute = createRouteMatcher([
  '/',
  '/sign-in(.*)',
  '/sign-up(.*)',
  '/api/webhooks(.*)',
  '/api/health',
]);

export default clerkMiddleware(async (auth, request: NextRequest) => {
  if (isProtectedRoute(request)) {
    await auth.protect();
  }

  // ✅ FIX 3: Headers de sécurité sur chaque réponse
  const response = NextResponse.next();
  response.headers.set('X-Frame-Options', 'DENY');
  response.headers.set('X-Content-Type-Options', 'nosniff');

  return response;
});

export const config = {
  matcher: [
    '/((?!_next|[^?]*\\.(?:html?|css|js(?!on)|jpe?g|webp|png|gif|svg|ttf|woff2?|ico|csv|docx?|xlsx?|zip|webmanifest)).*)',
