### ✅ APRÈS (corrigé — fonctions de sécurité ajoutées)
```typescript
// ✅ FIX 1: Limites de sécurité
const MAX_FILE_SIZE = 1024 * 1024;  // 1MB max
const MAX_FILES_PER_SCAN = 500;
const REGEX_TIMEOUT_MS = 5000;       // 5s timeout par fichier

// ✅ FIX 2: Regex avec timeout anti-ReDoS
function safeRegexScan(
  content: string,
  pattern: RegExp,
  filePath: string,
): RegExpExecArray[] {
  const results: RegExpExecArray[] = [];
  const startTime = Date.now();
  const regex = new RegExp(pattern.source, pattern.flags);

  let match: RegExpExecArray | null;
  while ((match = regex.exec(content)) !== null) {
    // ✅ Timeout protection
    if (Date.now() - startTime > REGEX_TIMEOUT_MS) {
      console.warn(`⚠  Regex timeout sur ${filePath}`);
      break;
    }
    results.push(match);
    if (match[0].length === 0) regex.lastIndex++;
  }
  return results;
}

// ✅ FIX 3: Validation des fichiers avant scan
function validateFileForScan(filePath: string, content: string): string | null {
  if (!content || content.trim().length === 0) return null;

  // Trop gros = probablement un bundle minifié
  if (content.length > MAX_FILE_SIZE) {
    console.warn(`⚠  Fichier trop gros: ${filePath}`);
    return null;
  }

  // Fichiers binaires
  if (content.includes('\0')) return null;

  // Dossiers à ignorer
  const skip = ['node_modules', '/dist/', '/build/', '/.next/'];
  if (skip.some((p) => filePath.includes(p))) return null;

  return content;
}

// ✅ FIX 4: Déduplication des résultats
function deduplicateFindings(findings: ScanFinding[]): ScanFinding[] {
  const seen = new Set<string>();
  return findings.filter((f) => {
    const key = `${f.file}:${f.line}:${f.rule}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
```

### 🔑 Ce qui a changé :
| Change | Pourquoi |
|--------|----------|
| `MAX_FILE_SIZE = 1MB` | Empêche le scan de bundles énormes |
| `REGEX_TIMEOUT_MS = 5s` | Protection contre ReDoS |
| `validateFileForScan()` | Skip fichiers binaires, node_modules, etc. |
| `safeRegexScan()` | Timeout + protection boucle infinie |
| `deduplicateFindings()` | Évite les doublons dans les rapports |

